+func TestPayloadTypeName_Nil(t *testing.T) {
+	t.Parallel()
+	got := payloadTypeName(nil)
+	if got != "nil" {
+		t.Errorf("payloadTypeName(nil) = %q, want %q", got, "nil")
+	}
+}
